## 3. GraphQL Service (gRPC Client)

파일 위치: `graphql/src/main/kotlin/com/maum/backend/service/profile/ProfileService.kt`

```kotlin
@Service
class ProfileService {
    @GrpcClient("profile-grpc")
    private lateinit var stub: ProfileServiceGrpc.ProfileServiceBlockingStub

    fun getMyProfile(userId: String): GetProfileResponse {
        val request = GetProfileRequest.newBuilder()
            .setUserId(userId)
            .build()
        return try {
            stub.getProfile(request)
        } catch (e: StatusRuntimeException) {
            when (e.status.code) {
                Status.Code.NOT_FOUND ->
                    throw CustomGraphQLException("PROFILE_NOT_FOUND", e.status.description)
                else ->
                    throw CustomGraphQLException("INTERNAL_ERROR", "서비스 오류")
            }
        }
    }

    fun updateProfile(userId: String, input: UpdateProfileInput): UpdateProfileResponse {
        val builder = UpdateProfileRequest.newBuilder().setUserId(userId)

        // Partial Update: null이 아닌 필드만 설정
        input.nickname?.let        { builder.setNickname(it) }
        input.bio?.let             { builder.setBio(it) }
        input.profileImageUrl?.let { builder.setProfileImageUrl(it) }
        input.birthDate?.let       { builder.setBirthDate(it) }
        input.gender?.let          { builder.setGender(it.toProto()) }
        input.interests?.let       { builder.addAllInterests(it) }
        input.location?.let {
            builder.setLocation(
                LocationProto.newBuilder()
                    .setCity(it.city)
                    .setRegion(it.region)
                    .setCountryCode(it.countryCode)
                    .build()
            )
        }
        input.voiceIntroUrl?.let   { builder.setVoiceIntroUrl(it) }
        input.clearVoiceIntro?.let { builder.setClearVoiceIntro(it) }

        return try {
            stub.updateProfile(builder.build())
        } catch (e: StatusRuntimeException) {
            when (e.status.code) {
                Status.Code.INVALID_ARGUMENT ->
                    throw CustomGraphQLException("VALIDATION_ERROR", e.status.description)
                Status.Code.ALREADY_EXISTS ->
                    throw CustomGraphQLException("NICKNAME_DUPLICATE", e.status.description)
                Status.Code.NOT_FOUND ->
                    throw CustomGraphQLException("PROFILE_NOT_FOUND", e.status.description)
                else ->
                    throw CustomGraphQLException("INTERNAL_ERROR", "서비스 오류")
            }
        }
    }
}
```

