## 4. gRPC Proto 정의

파일 위치: `protobuf/src/main/proto/profile/profile_service.proto`

```protobuf
syntax = "proto3";

package profile;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.profile";

// ──────────────────────────────────────────
// 서비스 정의
// ──────────────────────────────────────────

service ProfileService {
  rpc GetProfile    (GetProfileRequest)    returns (GetProfileResponse);
  rpc UpdateProfile (UpdateProfileRequest) returns (UpdateProfileResponse);
}

// ──────────────────────────────────────────
// Enum
// ──────────────────────────────────────────

enum Gender {
  GENDER_UNSPECIFIED     = 0;  // 미설정 (proto3 기본값)
  GENDER_MALE            = 1;
  GENDER_FEMALE          = 2;
  GENDER_NON_BINARY      = 3;
  GENDER_PREFER_NOT_SAY  = 4;
}

// ──────────────────────────────────────────
// 공통 메시지
// ──────────────────────────────────────────

message Location {
  string city         = 1;
  string region       = 2;
  string country_code = 3;  // ISO 3166-1 alpha-2
}

message Profile {
  string   user_id          = 1;
  string   nickname         = 2;
  string   bio              = 3;
  string   profile_image_url = 4;
  string   birth_date       = 5;  // "YYYY-MM-DD"
  Gender   gender           = 6;
  repeated string interests = 7;
  Location location         = 8;
  string   voice_intro_url  = 9;
  string   updated_at       = 10; // ISO 8601
}

// ──────────────────────────────────────────
// GetProfile
// ──────────────────────────────────────────

message GetProfileRequest {
  string user_id = 1;
}

message GetProfileResponse {
  Profile profile = 1;
}

// ──────────────────────────────────────────
// UpdateProfile  (Partial Update)
//   optional 키워드: 필드가 설정됐는지 여부를 has_xxx()로 판별
//   → null과 "미전송"을 구분하기 위해 proto3 optional 사용
// ──────────────────────────────────────────

message UpdateProfileRequest {
  string            user_id           = 1;   // 필수

  optional string   nickname          = 2;
  optional string   bio               = 3;
  optional string   profile_image_url = 4;
  optional string   birth_date        = 5;
  optional Gender   gender            = 6;
  repeated string   interests         = 7;   // 전송 시 전체 덮어쓰기
  optional Location location          = 8;
  optional string   voice_intro_url   = 9;
  optional bool     clear_voice_intro = 10;  // true이면 voice_intro_url 삭제
}

message UpdateProfileResponse {
  Profile profile = 1;
}
