## 5. gRPC Server 구현 (프로필 마이크로서비스)

파일 위치: `profile-service/src/main/kotlin/com/maum/backend/controller/ProfileGrpcService.kt`

```kotlin
@GrpcService
class ProfileGrpcService(
    private val profileService: ProfileDomainService,
) : ProfileServiceGrpc.ProfileServiceImplBase() {

    override fun getProfile(
        request: GetProfileRequest,
        responseObserver: StreamObserver<GetProfileResponse>,
    ) {
        try {
            val profile = profileService.getProfile(request.userId)
            responseObserver.onNext(
                GetProfileResponse.newBuilder()
                    .setProfile(profile.toProto())
                    .build()
            )
            responseObserver.onCompleted()
        } catch (e: ProfileNotFoundException) {
            responseObserver.onError(
                Status.NOT_FOUND
                    .withDescription("프로필을 찾을 수 없습니다: ${request.userId}")
                    .asRuntimeException()
            )
        }
    }

    override fun updateProfile(
        request: UpdateProfileRequest,
        responseObserver: StreamObserver<UpdateProfileResponse>,
    ) {
        try {
            // Partial Update: has_xxx() 로 설정 여부 판별
            val command = UpdateProfileCommand(
                userId           = request.userId,
                nickname         = if (request.hasNickname())        request.nickname        else null,
                bio              = if (request.hasBio())             request.bio             else null,
                profileImageUrl  = if (request.hasProfileImageUrl()) request.profileImageUrl else null,
                birthDate        = if (request.hasBirthDate())       request.birthDate       else null,
                gender           = if (request.hasGender())          request.gender.toDomain() else null,
                interests        = if (request.interestsList.isNotEmpty()) request.interestsList else null,
                location         = if (request.hasLocation())        request.location.toDomain() else null,
                voiceIntroUrl    = if (request.hasVoiceIntroUrl())   request.voiceIntroUrl   else null,
                clearVoiceIntro  = if (request.hasClearVoiceIntro()) request.clearVoiceIntro else false,
            )

            val updated = profileService.updateProfile(command)
            responseObserver.onNext(
                UpdateProfileResponse.newBuilder()
                    .setProfile(updated.toProto())
                    .build()
            )
            responseObserver.onCompleted()

        } catch (e: ValidationException) {
            responseObserver.onError(
                Status.INVALID_ARGUMENT
                    .withDescription(e.message)
                    .asRuntimeException()
            )
        } catch (e: NicknameDuplicateException) {
            responseObserver.onError(
                Status.ALREADY_EXISTS
                    .withDescription("이미 사용 중인 닉네임입니다.")
                    .asRuntimeException()
            )
        } catch (e: ProfileNotFoundException) {
            responseObserver.onError(
                Status.NOT_FOUND
                    .withDescription("프로필을 찾을 수 없습니다.")
                    .asRuntimeException()
            )
        } catch (e: Exception) {
            responseObserver.onError(
                Status.INTERNAL
                    .withDescription("Internal error")
                    .asRuntimeException()
            )
        }
    }
}
